'use client';

import type { ColumnDef } from '@tanstack/react-table';
import {
  Can,
  DataTableShell,
  LoadingSkeleton,
  PageHeader,
  StatusBadge,
} from '@/components/shared';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { PERMISSIONS } from '@/constants/permissions';
import { useAuth } from '@/features/auth/hooks/use-auth';

type DemoRow = { id: string; trip: string; status: string };

const demoColumns: ColumnDef<DemoRow, unknown>[] = [
  { accessorKey: 'trip', header: 'Trip' },
  {
    accessorKey: 'status',
    header: 'Status',
    cell: ({ row }) => <StatusBadge status={row.original.status} domain="trip" />,
  },
];

export default function DashboardPage() {
  const { user } = useAuth();

  return (
    <div className="flex flex-1 flex-col gap-6 p-4 lg:p-6">
      <PageHeader
        title="Dashboard"
        description={`Welcome back, ${user?.fullName ?? 'User'}. Overview widgets and KPIs will be added in a later phase.`}
      />

      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Trips today</CardTitle>
            <CardDescription>Placeholder KPI</CardDescription>
          </CardHeader>
          <CardContent className="text-2xl font-semibold">—</CardContent>
        </Card>
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Active vehicles</CardTitle>
            <CardDescription>Placeholder KPI</CardDescription>
          </CardHeader>
          <CardContent className="text-2xl font-semibold">—</CardContent>
        </Card>
        <Can permission={PERMISSIONS.VIEW_REPORTS}>
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Reports</CardTitle>
              <CardDescription>Permission-gated card</CardDescription>
            </CardHeader>
            <CardContent className="text-sm text-muted-foreground">
              Visible with <code className="text-xs">VIEW_REPORTS</code>
            </CardContent>
          </Card>
        </Can>
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Status samples</CardTitle>
            <CardDescription>Design system tokens</CardDescription>
          </CardHeader>
          <CardContent className="flex flex-wrap gap-2">
            <StatusBadge status="PENDING" domain="trip" />
            <StatusBadge status="IN_PROGRESS" domain="trip" />
            <StatusBadge status="AVAILABLE" domain="vehicle" />
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Shared components preview</CardTitle>
          <CardDescription>DataTable shell and loading skeleton foundations</CardDescription>
        </CardHeader>
        <CardContent className="space-y-8">
          <DataTableShell
            columns={demoColumns}
            data={[]}
            searchValue=""
            onSearchChange={() => undefined}
            emptyTitle="No trips yet"
            emptyDescription="Trip data will appear here when the trips module is implemented."
          />
          <LoadingSkeleton variant="table" />
        </CardContent>
      </Card>
    </div>
  );
}
